1503 /// If all arguments of the intrinsic are unary shuffles with the same mask,
1504 /// try to shuffle after the intrinsic.
1505 Instruction *
1506 InstCombinerImpl::foldShuffledIntrinsicOperands(IntrinsicInst *II) {
1507   if (!II->getType()->isVectorTy() ||
1508       !isTriviallyVectorizable(II->getIntrinsicID()) ||
1509       !II->getCalledFunction()->isSpeculatable())
1510     return nullptr;
1511 
1512   Value *X;
1513   Constant *C;
1514   ArrayRef<int> Mask;
1515   auto *NonConstArg = find_if_not(II->args(), [&II](Use &Arg) {
1516     return isa<Constant>(Arg.get()) ||
1517            isVectorIntrinsicWithScalarOpAtArg(II->getIntrinsicID(),
1518                                               Arg.getOperandNo(), nullptr);
1519   });
1520   if (!NonConstArg ||
1521       !match(NonConstArg, m_Shuffle(m_Value(X), m_Poison(), m_Mask(Mask))))
1522     return nullptr;
1523 
1524   // At least 1 operand must be a shuffle with 1 use because we are creating 2
1525   // instructions.
1526   if (none_of(II->args(), match_fn(m_OneUse(m_Shuffle(m_Value(), m_Value())))))
1527     return nullptr;
1528 
1529   // See if all arguments are shuffled with the same mask.
1530   SmallVector<Value *, 4> NewArgs;
1531   Type *SrcTy = X->getType();
1532   for (Use &Arg : II->args()) {
1533     if (isVectorIntrinsicWithScalarOpAtArg(II->getIntrinsicID(),
1534                                            Arg.getOperandNo(), nullptr))
1535       NewArgs.push_back(Arg);
1536     else if (match(&Arg,
1537                    m_Shuffle(m_Value(X), m_Poison(), m_SpecificMask(Mask))) &&
1538              X->getType() == SrcTy)
1539       NewArgs.push_back(X);
1540     else if (match(&Arg, m_ImmConstant(C))) {
1541       // If it's a constant, try find the constant that would be shuffled to C.
1542       if (Constant *ShuffledC =
1543               unshuffleConstant(Mask, C, cast<VectorType>(SrcTy)))
1544         NewArgs.push_back(ShuffledC);
1545       else
1546         return nullptr;
1547     } else
1548       return nullptr;
1549   }
1550 
1551   // intrinsic (shuf X, M), (shuf Y, M), ... --> shuf (intrinsic X, Y, ...), M
1552   Instruction *FPI = isa<FPMathOperator>(II) ? II : nullptr;
1553   // Result type might be a different vector width.
1554   // TODO: Check that the result type isn't widened?
1555   VectorType *ResTy =
1556       VectorType::get(II->getType()->getScalarType(), cast<VectorType>(SrcTy));
1557   Value *NewIntrinsic =
1558       Builder.CreateIntrinsic(ResTy, II->getIntrinsicID(), NewArgs, FPI);
1559   return new ShuffleVectorInst(NewIntrinsic, Mask);
1560 }
