1600 /// Fold the following cases and accepts bswap and bitreverse intrinsics:
1601 ///   bswap(logic_op(bswap(x), y)) --> logic_op(x, bswap(y))
1602 ///   bswap(logic_op(bswap(x), bswap(y))) --> logic_op(x, y) (ignores multiuse)
1603 template <Intrinsic::ID IntrID>
1604 static Instruction *foldBitOrderCrossLogicOp(Value *V,
1605                                              InstCombiner::BuilderTy &Builder) {
1606   static_assert(IntrID == Intrinsic::bswap || IntrID == Intrinsic::bitreverse,
1607                 "This helper only supports BSWAP and BITREVERSE intrinsics");
1608 
