1610   // Find bitwise logic op. Check that it is a BinaryOperator explicitly so we
1611   // don't match ConstantExpr that aren't meaningful for this transform.
1612   if (match(V, m_OneUse(m_BitwiseLogic(m_Value(X), m_Value(Y)))) &&
1613       isa<BinaryOperator>(V)) {
1614     Value *OldReorderX, *OldReorderY;
1615     BinaryOperator::BinaryOps Op = cast<BinaryOperator>(V)->getOpcode();
1616 
1617     // If both X and Y are bswap/bitreverse, the transform reduces the number
1618     // of instructions even if there's multiuse.
1619     // If only one operand is bswap/bitreverse, we need to ensure the operand
1620     // have only one use.
1621     if (match(X, m_Intrinsic<IntrID>(m_Value(OldReorderX))) &&
1622         match(Y, m_Intrinsic<IntrID>(m_Value(OldReorderY)))) {
1623       return BinaryOperator::Create(Op, OldReorderX, OldReorderY);
1624     }
1625 
1626     if (match(X, m_OneUse(m_Intrinsic<IntrID>(m_Value(OldReorderX))))) {
1627       Value *NewReorder = Builder.CreateUnaryIntrinsic(IntrID, Y);
1628       return BinaryOperator::Create(Op, OldReorderX, NewReorder);
1629     }
1630 
1631     if (match(Y, m_OneUse(m_Intrinsic<IntrID>(m_Value(OldReorderY))))) {
1632       Value *NewReorder = Builder.CreateUnaryIntrinsic(IntrID, X);
1633       return BinaryOperator::Create(Op, NewReorder, OldReorderY);
1634     }
1635   }
1636   return nullptr;
1637 }
